function parseCandidate(raw) {
  try {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed;
    }
  } catch {}
  return null;
}

function normalizeText(raw) {
  let text = String(raw ?? '').trim();
  if (!text) {
    throw new Error('Surface extraction model output is empty.');
  }

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    text = fenced[1].trim();
  }

  return text;
}

function extractObject(text) {
  const normalized = normalizeText(text);
  const candidates = [normalized];

  const firstObjectStart = normalized.indexOf('{');
  const lastObjectEnd = normalized.lastIndexOf('}');
  if (firstObjectStart >= 0 && lastObjectEnd > firstObjectStart) {
    candidates.push(normalized.slice(firstObjectStart, lastObjectEnd + 1));
  }

  for (const candidate of candidates) {
    const parsed = parseCandidate(candidate);
    if (parsed) return parsed;
  }

  throw new Error('Could not extract valid JSON from model output.');
}

function normalizeBucket(payload, key) {
  const bucket = payload?.[key];
  if (!Array.isArray(bucket)) return [];

  const seen = new Set();
  const out = [];
  for (const entry of bucket) {
    const name = String(entry?.name ?? '').trim();
    if (!name) continue;
    const normalized = name.replace(/\s+/g, ' ').trim();
    const dedupeKey = normalized.toLowerCase();
    if (seen.has(dedupeKey)) continue;
    seen.add(dedupeKey);
    out.push({ name: normalized });
  }
  return out;
}

const item = $input.first() ?? { json: {}, binary: {} };
const parsed = extractObject(item?.json?.text);

const screens = normalizeBucket(parsed, 'screens');
const modals = normalizeBucket(parsed, 'modals');
const dialogs = normalizeBucket(parsed, 'dialogs');

const output = {};
if (screens.length) output.screens = screens;
if (modals.length) output.modals = modals;
if (dialogs.length) output.dialogs = dialogs;

if (!Object.keys(output).length) {
  throw new Error('Model output did not contain any valid screens/modals/dialogs entries.');
}

return [{
  json: {
    ...(item.json ?? {}),
    designSurfacePlan: JSON.stringify(output, null, 2),
    designSurfacePlanObject: output,
    surfaceCounts: {
      screens: screens.length,
      modals: modals.length,
      dialogs: dialogs.length,
      total: screens.length + modals.length + dialogs.length,
    },
    response: JSON.stringify(output, null, 2),
  },
  binary: item?.binary ?? {},
}];

async function getTextBinary(itemIndex, item, propertyName, fallbackFileName) {
  const binary = item.binary?.[propertyName];
  if (!binary) return null;

  const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, propertyName);
  return {
    key: propertyName,
    fileName: binary.fileName || fallbackFileName,
    mimeType: String(binary.mimeType || ''),
    content: buffer.toString('utf8'),
  };
}

const item = $input.first() ?? { json: {}, binary: {} };
const binary = item.binary ?? {};
const preferredKeys = ['requirements', 'requirementsMd', 'requirements_md', 'requirementsFile', 'requirements_file'];

let requirements = null;
for (const key of preferredKeys) {
  requirements = await getTextBinary.call(this, 0, item, key, 'requirements.md');
  if (requirements) break;
}

if (!requirements) {
  for (const [key, entry] of Object.entries(binary)) {
    const mime = String(entry?.mimeType ?? '').toLowerCase();
    const extRaw = String(entry?.fileExtension ?? '').toLowerCase();
    const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;
    const fileName = String(entry?.fileName ?? key).toLowerCase();
    const likelyText = mime.startsWith('text/') || ['md', 'txt', 'markdown'].includes(ext) || fileName.endsWith('.md') || fileName.endsWith('.txt');
    if (!likelyText) continue;

    requirements = await getTextBinary.call(this, 0, item, key, 'requirements.md');
    if (requirements) break;
  }
}

if (!requirements) {
  throw new Error('Missing requirements markdown file in form upload.');
}

const requirementsText = String(requirements.content || '').trim();
if (!requirementsText) {
  throw new Error('Requirements specification is empty.');
}

const userPrompt = [
  '------------------------------------------------',
  'REQUIREMENTS SPECIFICATION INPUT',
  '------------------------------------------------',
  requirementsText,
].join('\n');

return [{
  json: {
    ...(item.json ?? {}),
    requirementsBinaryProperty: requirements.key,
    requirementsFile: requirements.fileName,
    requirementsMimeType: requirements.mimeType,
    userPrompt,
  },
  binary,
}];
